const body = $json.body || {};
const missing = [];
if (!body.sap_rows || body.sap_rows.length === 0) missing.push('sap_rows');
if (!body.filename) missing.push('filename');
if (!body.created_by) missing.push('created_by');
if (missing.length > 0) {
  return [{ json: { error: true, message: 'Missing required fields: ' + missing.join(', ') } }];
}
return [{ json: { error: false, ...body } }];

const body = $('Webhook - Receive SAP Upload').first().json.body;
const rows = body.sap_rows || [];
const filename = body.filename || 'unknown.xlsx';
const createdBy = body.created_by || 'system';
const projectName = body.project_name || null;
const projectCode = body.project_code || null;
const projectLocation = body.project_location || null;
const client = body.client || null;
const consultant = body.consultant || null;

function cleanDescription(materialId) {
  if (!materialId) return '';
  // Strip SAP code in parentheses at end: "ITEM NAME (1000001234)" → "ITEM NAME"
  return materialId.replace(/\s*\(\d{10}\)\s*$/, '').replace(/\s*\([A-Z0-9]{10}\)\s*$/, '').trim();
}

function extractSapCode(materialId) {
  if (!materialId) return null;
  const match = materialId.match(/\((\d{10})\)\s*$/);
  return match ? match[1] : null;
}

function extractBrand(itemDetails) {
  if (!itemDetails || !itemDetails.trim()) return null;
  const d = itemDetails.trim();
  // If item details looks like a brand hint (contains brand name or "brand:")
  if (d.toLowerCase().includes('brand:')) return d.replace(/brand:/i, '').trim();
  // If it's a short spec that looks like a brand (e.g. "HISENSE/OR ANY BRAND", "Jindal Shadeed")
  if (d.length < 60 && /brand|make|manufacturer|model/i.test(d)) return d;
  return null;
}

const activeItems = [];
const procuredItems = [];

for (const row of rows) {
  const status = (row.processing_status || '').toLowerCase();
  const cleaned = {
    pr_number: row.pr_number,
    item_number: row.item_number,
    material_id: row.material_id,
    description: cleanDescription(row.material_id),
    sap_material_code: extractSapCode(row.material_id),
    item_details: row.item_details || null,
    brand_hint: extractBrand(row.item_details),
    quantity: row.quantity,
    unit: row.unit || 'pcs',
    processing_status: row.processing_status,
    delivery_date: row.delivery_date
  };
  if (status.includes('po created') || status.includes('(b)')) {
    procuredItems.push(cleaned);
  } else {
    activeItems.push(cleaned);
  }
}

if (activeItems.length === 0) {
  return [{ json: { error: true, message: 'No active items found. All items may have POs already created.' } }];
}

return [{
  json: {
    error: false,
    filename,
    created_by: createdBy,
    project_name: projectName,
    project_code: projectCode,
    project_location: projectLocation,
    client,
    consultant,
    total_rows: rows.length,
    active_items: activeItems,
    procured_items: procuredItems,
    active_count: activeItems.length,
    procured_count: procuredItems.length
  }
}];

const data = $json;
const activeItems = data.active_items || [];
const groups = data.procurement_groups || [];
const groupList = groups.join(', ');

const itemsText = activeItems.slice(0, 25).map((item, i) => {
  return `Item ${i+1}:
  PR: ${item.pr_number}
  SAP Item No: ${item.item_number}
  Description: ${item.description}
  Item Details: ${item.item_details || 'none'}
  Quantity: ${item.quantity} ${item.unit || ''}
  Delivery Date: ${item.delivery_date}`;
}).join('\n\n');

const prompt = `You are a procurement categorisation assistant for Sarooj Construction Company, Oman.

Categorise each item into one of these procurement groups (use EXACTLY these values):
${groupList}

These groups represent the pools of vendors Sarooj sends RFQs to. Choose the single best-fit group for each item based on its description. If an item does not clearly fit any group, use "Building Materials & Accessories" as the default.

Use the item description as the primary signal.

Return ONLY a valid JSON array. No explanation, no markdown, no backticks.

For each item return:
{
  "item_index": number (0-based),
  "description": "item description",
  "category": "one group from the list above",
  "confidence": "high or low",
  "confidence_reason": "only if low, else null"
}

Items:

${itemsText}`;

return [{ json: { ...data, categorisation_prompt: prompt, unknown_items: activeItems, known_items: [] } }];

const rawText = $json.output || '[]';
const promptData = $('Build Categorisation Prompt').first().json;
const unknownItems = promptData.unknown_items || [];
const knownItems = promptData.known_items || [];
const parseNode = $('Parse SAP Rows + Filter Status').first().json;
const mergeNode = $('Merge Procurement Context').first().json;

let aiCategorised = [];
try {
  const clean = rawText.replace(/```json/g, '').replace(/```/g, '').trim();
  const match = clean.match(/\[.*\]/s);
  aiCategorised = JSON.parse(match ? match[0] : clean);
} catch(e) {
  aiCategorised = unknownItems.map((item, i) => ({
    item_index: i, category: 'Unknown', confidence: 'low',
    confidence_reason: 'AI parsing failed: ' + e.message
  }));
}

function fallbackCategory(description) {
  const d = (description || '').toLowerCase();
  if (/shovel|spade|pick|hammer|hand tool/.test(d)) return 'Building Materials & Accessories';
  if (/unistrut|channel|strut|bracket|hanger wire|suspension/.test(d)) return 'Building Materials & Accessories';
  if (/gypsum|ceiling tile|plaster|drywall|false ceiling/.test(d)) return 'Building Materials & Accessories';
  if (/screw|bolt|nut|washer|rivet|fastener|anchor/.test(d)) return 'Fasteners & Fixings';
  if (/tape|glue|adhesive|sealant|pvc glue/.test(d)) return 'Pipes, Fittings & Valves';
  if (/pipe|tube|socket|elbow|tee/.test(d)) return 'Pipes, Fittings & Valves';
  if (/valve|fitting|adaptor|coupling|nrv|tap|faucet/.test(d)) return 'Pipes, Fittings & Valves';
  if (/wire|cable|conductor|flex/.test(d)) return 'Electrical Materials';
  if (/switch|breaker|fuse|relay|diode|capacitor|resistor|electrical|electric|panel/.test(d)) return 'Electrical Materials';
  if (/split ac|window ac|air condition|ac unit/.test(d)) return 'HVAC & Cooling';
  if (/water cooler|cooler|thermos|dispenser|water heater/.test(d)) return 'Welfare & Camp';
  if (/pillow|mattress|bed|bedsheet|sheet|blanket|towel|linen/.test(d)) return 'Welfare & Camp';
  if (/ro plant|ro system|water filter|filter catridge|water treatment/.test(d)) return 'Pipes, Fittings & Valves';
  if (/pump|motor|compressor/.test(d)) return 'Pumps & Mechanical';
  if (/rebar|bar|rod|steel bar|deformed|straight bar|ht bar|h\.t\./.test(d)) return 'Steel & Rebar';
  if (/transport|freight|logistics|delivery charge|haulage/.test(d)) return 'Logistics & Services';
  if (/hvac|air handling|ahu|chiller/.test(d)) return 'HVAC & Cooling';
  if (/cement|opc|ppc/.test(d)) return 'Cement & Concrete';
  if (/aggregate|sand|gravel|crusher/.test(d)) return 'Aggregates & Sand';
  if (/scaffold|formwork|shuttering|plywood/.test(d)) return 'Scaffolding & Formwork';
  return 'Building Materials & Accessories';
}

const allCategorised = [...knownItems];
for (let i = 0; i < unknownItems.length; i++) {
  const aiResult = aiCategorised.find(r => Number(r.item_index) === i) || aiCategorised[i];
  let category = aiResult ? (aiResult.category || 'Unknown') : 'Unknown';
  let confidence = aiResult ? (aiResult.confidence || 'low') : 'low';
  if (category === 'Unknown') {
    category = fallbackCategory(unknownItems[i].description);
    confidence = 'medium';
  }
  allCategorised.push({
    ...unknownItems[i], category, confidence,
    confidence_reason: (aiResult && aiResult.confidence_reason) ? aiResult.confidence_reason : null
  });
}

const hitlItems = allCategorised.filter(item => item.category === 'Unknown');
const readyItems = allCategorised.filter(item => item.category !== 'Unknown');

// GROUP BY CATEGORY ONLY — all PRs combined into one RFQ per category
const groups = {};
for (const item of readyItems) {
  const key = item.category;
  if (!groups[key]) {
    groups[key] = {
      category: item.category,
      rfq_type: item.rfq_type || 'materials',
      needs_scope_documents: false,
      items: []
    };
  }
  if (item.rfq_type === 'subcontract') groups[key].rfq_type = 'subcontract';
  groups[key].items.push(item);
}

const rfqGroups = Object.values(groups);

return [{
  json: {
    rfq_groups: rfqGroups,
    group_count: rfqGroups.length,
    hitl_items: hitlItems,
    hitl_count: hitlItems.length,
    procured_items: parseNode.procured_items,
    procured_count: parseNode.procured_count,
    filename: parseNode.filename,
    created_by: parseNode.created_by,
    project_name: parseNode.project_name,
    project_code: parseNode.project_code,
    project_location: parseNode.project_location,
    client: parseNode.client,
    consultant: parseNode.consultant,
    terms_and_conditions: mergeNode.terms_and_conditions || ''
  }
}];

const now = new Date();
const yy = String(now.getFullYear()).slice(2);
const mm = String(now.getMonth() + 1).padStart(2, '0');
const period = yy + mm;
const data = $json;
const groups = data.rfq_groups || [];
let materialCount = 0;
let subcontractCount = 0;

return groups.map((group, i) => {
  const isSubcontract = group.rfq_type === 'subcontract';
  const type_index = isSubcontract ? subcontractCount++ : materialCount++;
  // Collect all PR numbers from items
  const prNumbers = [...new Set((group.items || []).map(it => it.pr_number).filter(Boolean))].sort();
  return {
    json: {
      ...group,
      period,
      group_index: i,
      type_index,
      base_seq_mr: data.base_seq_mr,
      base_seq_sr: data.base_seq_sr,
      pr_numbers: prNumbers,
      created_by: data.created_by,
      project_name: data.project_name,
      project_code: data.project_code,
      project_location: data.project_location,
      client: data.client,
      consultant: data.consultant,
      filename: data.filename,
      terms_and_conditions: data.terms_and_conditions,
      procured_items: data.procured_items,
      procured_count: data.procured_count,
      hitl_items: data.hitl_items,
      hitl_count: data.hitl_count
    }
  };
});

const groups = $('Prepare RFQ Groups').all();
// Highest existing sequence for this period+type, read from the DB lookup (robust to empty).
let baseMR = 0, baseSR = 0;
for (const r of $('Supabase - Get Last RFQ Reference').all()) {
  const j = r.json || {};
  const refStr = j.rfq_reference || (Array.isArray(j) && j[0] && j[0].rfq_reference) || null;
  if (!refStr) continue;
  const m = String(refStr).match(/^(MR|SR)-\d+-(\d+)$/);
  if (!m) continue;
  const seq = parseInt(m[2], 10) || 0;
  if (m[1] === 'MR') baseMR = Math.max(baseMR, seq); else baseSR = Math.max(baseSR, seq);
}
return groups.map((gr) => {
  const group = gr.json;
  const isSubcontract = group.rfq_type === 'subcontract';
  const prefix = isSubcontract ? 'SR' : 'MR';
  const base = isSubcontract ? baseSR : baseMR;
  const nextSeq = base + group.type_index + 1;
  const reference = prefix + '-' + group.period + '-' + String(nextSeq).padStart(3, '0');
  const prNumbers = [...new Set((group.items || []).map(i => i.pr_number).filter(Boolean))];
  return { json: { ...group, rfq_reference: reference, pr_numbers: prNumbers, item_count: group.items.length } };
});

const allGroups = $('Map Vendor Categories').all();
const allVendorItems = $('Query Vendors HTTP').all();
const parseData = $('Parse SAP Rows + Filter Status').first().json;
const mergeData = $('Merge Procurement Context').first().json;

const vendorsByGroup = {};
allVendorItems.forEach((item) => {
  const groupIdx = (item.pairedItem && item.pairedItem.item !== undefined) ? item.pairedItem.item : 0;
  if (!vendorsByGroup[groupIdx]) vendorsByGroup[groupIdx] = [];
  if (item.json && item.json.vendor_id) vendorsByGroup[groupIdx].push(item.json);
});

return allGroups.map((groupItem, i) => {
  const group = groupItem.json;
  const vendors = vendorsByGroup[i] || [];
  // TEST_ALWAYS recipients appended to every RFQ (testing). Limit-proof (post-query). REMOVE BEFORE GO-LIVE.
  // Test recipients are config-driven (system_settings: dispatch_test_mode +
  // dispatch_test_recipients), read from the Fetch T&Cs and DB Categories node.
  // Admin flips dispatch_test_mode in the app (Settings). No emails hardcoded here.
  const _tcRows = $('Fetch T&Cs and DB Categories').all();
  const _modeRow = _tcRows.find(r => r.json && r.json.setting_key === 'dispatch_test_mode');
  const _testMode = ((_modeRow && _modeRow.json.setting_value) || 'off');
  let TEST_RECIPIENTS = [];
  if (_testMode === 'on') {
    const _recRow = _tcRows.find(r => r.json && r.json.setting_key === 'dispatch_test_recipients');
    try { TEST_RECIPIENTS = JSON.parse((_recRow && _recRow.json.setting_value) || '[]'); }
    catch (e) { TEST_RECIPIENTS = []; }
  }
  { const _seen = new Set(vendors.map(x => x.vendor_id)); for (const t of TEST_RECIPIENTS) { if (!_seen.has(t.vendor_id)) { vendors.push(t); _seen.add(t.vendor_id); } } }

  const aiNotes = [];
  if (vendors.length === 0) aiNotes.push(`No vendors found for category: ${group.category}.`);
  else if (vendors.length < 3) aiNotes.push(`Only ${vendors.length} vendor(s) found for ${group.category}.`);

  // Get unique PR numbers for this RFQ
  const prNumbers = [...new Set((group.items || []).map(i => i.pr_number).filter(Boolean))].sort();

  // Build subject line — Option C: first PR + count if multiple
  let prLabel;
  if (prNumbers.length === 1) {
    prLabel = `PR# ${prNumbers[0]}`;
  } else if (prNumbers.length === 2) {
    prLabel = `PR# ${prNumbers[0]} & ${prNumbers[1]}`;
  } else {
    prLabel = `PR# ${prNumbers[0]} (+${prNumbers.length - 1} more)`;
  }

  // Today's date
  const today = new Date();
  const dd = String(today.getDate()).padStart(2,'0');
  const mm = String(today.getMonth()+1).padStart(2,'0');
  const yyyy = today.getFullYear();
  const dateStr = `${dd}-${mm}-${yyyy}`;

  const emailSubject = `SCC_ENQ_${dateStr}_${group.rfq_reference}, ${prLabel}_${group.category}`;

  // Build one flat table with PR Number as second column
  // Sort items by PR number then item number
  const sortedItems = [...(group.items || [])].sort((a, b) => {
    if (a.pr_number < b.pr_number) return -1;
    if (a.pr_number > b.pr_number) return 1;
    return (a.item_number || 0) - (b.item_number || 0);
  });

  const itemRows = sortedItems.map((itm, j) => {
    const brand = itm.brand_hint || '';
    return `<tr>
      <td style="border:1px solid #ccc;padding:5px;text-align:center;">${j+1}</td>
      <td style="border:1px solid #ccc;padding:5px;text-align:center;font-size:11px;color:#666;">${itm.pr_number}</td>
      <td style="border:1px solid #ccc;padding:5px;">${itm.description || itm.material_id}</td>
      <td style="border:1px solid #ccc;padding:5px;text-align:center;">${itm.quantity}</td>
      <td style="border:1px solid #ccc;padding:5px;text-align:center;">${itm.unit || 'Nos'}</td>
      <td style="border:1px solid #ccc;padding:5px;"></td>
      <td style="border:1px solid #ccc;padding:5px;"></td>
      <td style="border:1px solid #ccc;padding:5px;">${brand}</td>
      <td style="border:1px solid #ccc;padding:5px;"></td>
      <td style="border:1px solid #ccc;padding:5px;"></td>
    </tr>`;
  }).join('\n');

  const itemsTable = `<table style="border-collapse:collapse;width:100%;font-size:12px;">
  <thead>
    <tr style="background-color:#f5f0c8;">
      <th style="border:1px solid #ccc;padding:5px;text-align:center;">S.No</th>
      <th style="border:1px solid #ccc;padding:5px;text-align:center;">PR Number</th>
      <th style="border:1px solid #ccc;padding:5px;">Description</th>
      <th style="border:1px solid #ccc;padding:5px;text-align:center;">Quantity</th>
      <th style="border:1px solid #ccc;padding:5px;text-align:center;">Unit of Measurement</th>
      <th style="border:1px solid #ccc;padding:5px;text-align:center;">Unit Rate</th>
      <th style="border:1px solid #ccc;padding:5px;text-align:center;">Total Rate</th>
      <th style="border:1px solid #ccc;padding:5px;">Brand Offering By Supplier</th>
      <th style="border:1px solid #ccc;padding:5px;">Country of Origin</th>
      <th style="border:1px solid #ccc;padding:5px;">Stock Availability</th>
    </tr>
  </thead>
  <tbody>
    ${itemRows}
  </tbody>
</table>`;

  // T&Cs with placeholders replaced
  const projectLocation = parseData.project_location || 'Muscat';
  const tcs = (mergeData.terms_and_conditions || '')
    .replace(/\[project_location from upload form\]/gi, projectLocation)
    .replace(/\[project_location\]/gi, projectLocation)
    .replace(/\[deadline set on vendors tab\]/gi, '[To be confirmed]')
    .replace(/\[deadline\]/gi, '[To be confirmed]');

  const tcsHtml = tcs ? tcs.split('\n').map(line => line.trim() ? `<p style="margin:4px 0;">${line}</p>` : '').join('') : '';

  const emailBody = `<p>Dear [Contact Person],</p>
<p>We invite you to submit a quotation for the supply of items as per the following list:</p>

${itemsTable}

<br>
${tcsHtml}

<p style="color:#c00000;font-weight:bold;">Please reply directly to this email with your quotation. Responses received through any other channel will not be recorded in our system.</p>

<p>Thanks &amp; Regards,<br>
<strong>[SENDER_NAME]</strong><br>
Procurement Officer<br>
<strong>Sarooj Construction Company LLC</strong></p>`;

  const rfqTitle = `${group.category} Procurement`;

  return {
    json: {
      ...group,
      pr_numbers: prNumbers,
      vendors,
      vendor_count: vendors.length,
      ai_notes: aiNotes.join(' | '),
      items_table_html: itemsTable,
      covering_email_subject: emailSubject,
      covering_email_body: emailBody,
      rfq_title: rfqTitle
    },
    pairedItem: { item: i }
  };
});

// Email is now built in Merge Vendors + Build Email Prompt
// No AI email generation needed — read directly from that node
const mergeGroups = $('Merge Vendors + Build Email Prompt').all();
const parseData = $('Parse SAP Rows + Filter Status').first().json;

return mergeGroups.map((item, i) => {
  const group = item.json;
  return {
    json: {
      rfq_reference: group.rfq_reference,
      rfq_type: group.rfq_type,
      title: group.rfq_title || group.category,
      category: group.category,
      pr_number: group.pr_number,
      pr_numbers: [...new Set((group.items || []).map(it => it.pr_number).filter(Boolean))],
      items: group.items,
      vendors: group.vendors,
      vendor_count: group.vendor_count,
      ai_notes: group.ai_notes,
      needs_scope_documents: group.needs_scope_documents,
      covering_email_subject: group.covering_email_subject,
      covering_email_body: group.covering_email_body,
      items_table_html: group.items_table_html,
      period: group.period,
      created_by: group.created_by,
      project_name: group.project_name,
      project_code: group.project_code,
      project_location: group.project_location,
      client: group.client,
      consultant: group.consultant,
      sap_export_filename: parseData.filename,
      procured_items: parseData.procured_items,
      procured_count: parseData.procured_count
    },
    pairedItem: { item: i }
  };
});

// Input: N items with { ...draft, rfq_id } from Supabase - Insert RFQ (Code node).
// items array is already in $json — no cross-node lookups needed.
return $input.all().map((item, i) => {
  const rfq = item.json;
  const rfqId = rfq.rfq_id;
  const items = rfq.items || [];

  const rows = items.map((itm, j) => ({
    rfq_id: rfqId,
    item_number: j + 1,
    sap_item_number: itm.sap_item_number || null,
    sap_material_code: itm.sap_material_code || null,
    pr_number: itm.pr_number || null,
    description: itm.description,
    item_details: itm.item_details || null,
    quantity: itm.quantity,
    unit: itm.unit || 'Nos',
    delivery_date: itm.delivery_date || null,
    specification: itm.item_details || null
  }));

  // Spread full rfq data forward so downstream nodes still have vendors, etc.
  return { json: { ...rfq, rows }, pairedItem: { item: i } };
});

// Input: N items with { ...rfq_data, item_count } from Insert RFQ Items.
// vendors array is in $json — no cross-node lookups needed.
// contacts is a JSONB array — each element has { name, email, mobile, designation }
return $input.all().map((item, i) => {
  const rfq = item.json;
  const rfqId = rfq.rfq_id;
  const vendors = rfq.vendors || [];

  const rows = vendors.map(v => {
    const contacts = v.contacts || [];
    const primary = contacts[0] || {};
    return {
      rfq_id: rfqId,
      vendor_id: v.vendor_id,
      email_to: primary.email || null,
      contact_person: primary.name || null,
      matched_category: (v.categories && v.categories.length > 0) ? v.categories[0] : null,
      status: 'pending',
      response_received: false,
      ai_flag: (v.last_response_type === 'unresponsive' || v.status === 'unresponsive')
        ? 'Vendor was unresponsive in last outreach campaign'
        : null
    };
  });

  return { json: { ...rfq, rows }, pairedItem: { item: i } };
});

return $input.all().map((item, i) => {
  const rfq = item.json;
  return {
    json: {
      rfq_id: rfq.rfq_id,
      rfq_reference: rfq.rfq_reference,
      rfq_type: rfq.rfq_type,
      title: rfq.title,
      category: rfq.category,
      pr_number: rfq.pr_number,
      covering_email_subject: rfq.covering_email_subject,
      covering_email_body: rfq.covering_email_body,
      ai_notes: rfq.ai_notes,
      needs_scope_documents: rfq.needs_scope_documents,
      items: rfq.items,
      vendors: rfq.vendors,
      vendor_count: rfq.vendor_count,
      procured_items: rfq.procured_items,
      procured_count: rfq.procured_count,
      hitl_items: rfq.hitl_items || [],
      hitl_count: rfq.hitl_count || 0
    },
    pairedItem: { item: i }
  };
});

// Merge Supabase rfq_id back with original draft data
const allDrafts = $("Assemble RFQ Draft").all();
return $input.all().map((item, i) => {
  const resp = item.json;
  const rfqId = Array.isArray(resp) ? resp[0]?.rfq_id : resp?.rfq_id;
  const original = (allDrafts[i] || allDrafts[0]).json;
  return { json: { ...original, rfq_id: rfqId }, pairedItem: { item: i } };
});

// Restore original Prepare RFQ Items data after httpRequest
const allOriginals = $("Prepare RFQ Items").all();
return $input.all().map((item, i) => {
  const original = (allOriginals[i] || allOriginals[0]).json;
  const { rows: _, ...rest } = original;
  return { json: { ...rest, item_count: (original.rows || []).length }, pairedItem: { item: i } };
});

// Restore original Prepare RFQ Vendors data after httpRequest
const allOriginals = $("Prepare RFQ Vendors").all();
return $input.all().map((item, i) => {
  const original = (allOriginals[i] || allOriginals[0]).json;
  const { rows: _, ...rest } = original;
  return { json: { ...rest, vendor_count_inserted: (original.rows || []).length }, pairedItem: { item: i } };
