  const rfq = item.json;
  const rfqId = rfq.rfq_id;
  const items = rfq.items || [];

  const rows = items.map((itm, j) => ({
    rfq_id: rfqId,
    item_number: j + 1,
    sap_item_number: itm.sap_item_number || null,
    sap_material_code: itm.sap_material_code || null,
    pr_number: itm.pr_number || null,
    description: itm.description,
    item_details: itm.item_details || null,
    quantity: itm.quantity,
    unit: itm.unit || 'Nos',
    delivery_date: itm.delivery_date || null,
    specification: itm.item_details || null
  }));

  // Spread full rfq data forward so downstream nodes still have vendors, etc.
  return { json: { ...rfq, rows }, pairedItem: { item: i } };
});

// Input: N items with { ...rfq_data, item_count } from Insert RFQ Items.
// vendors array is in $json — no cross-node lookups needed.
// contacts is a JSONB array — each element has { name, email, mobile, designation }
return $input.all().map((item, i) => {
  const rfq = item.json;
  const rfqId = rfq.rfq_id;
  const vendors = rfq.vendors || [];

  const rows = vendors.map(v => {
    const contacts = v.contacts || [];
    const primary = contacts[0] || {};
    return {
      rfq_id: rfqId,
      vendor_id: v.vendor_id,
      email_to: primary.email || null,
      contact_person: primary.name || null,
      matched_category: (v.categories && v.categories.length > 0) ? v.categories[0] : null,
      status: 'pending',
      response_received: false,
      ai_flag: (v.last_response_type === 'unresponsive' || v.status === 'unresponsive')
        ? 'Vendor was unresponsive in last outreach campaign'
        : null
    };
  });

  return { json: { ...rfq, rows }, pairedItem: { item: i } };
});

return $input.all().map((item, i) => {
  const rfq = item.json;
  return {
    json: {
      rfq_id: rfq.rfq_id,
      rfq_reference: rfq.rfq_reference,
      rfq_type: rfq.rfq_type,
      title: rfq.title,
      category: rfq.category,
      pr_number: rfq.pr_number,
      covering_email_subject: rfq.covering_email_subject,
      covering_email_body: rfq.covering_email_body,
      ai_notes: rfq.ai_notes,
      needs_scope_documents: rfq.needs_scope_documents,
      items: rfq.items,
      vendors: rfq.vendors,
      vendor_count: rfq.vendor_count,
      procured_items: rfq.procured_items,
      procured_count: rfq.procured_count,
      hitl_items: rfq.hitl_items || [],
      hitl_count: rfq.hitl_count || 0
    },
    pairedItem: { item: i }
  };
});

// Merge Supabase rfq_id back with original draft data
const allDrafts = $("Assemble RFQ Draft").all();
return $input.all().map((item, i) => {
  const resp = item.json;
  const rfqId = Array.isArray(resp) ? resp[0]?.rfq_id : resp?.rfq_id;
  const original = (allDrafts[i] || allDrafts[0]).json;
  return { json: { ...original, rfq_id: rfqId }, pairedItem: { item: i } };
});

// Restore original Prepare RFQ Items data after httpRequest
const allOriginals = $("Prepare RFQ Items").all();
return $input.all().map((item, i) => {
  const original = (allOriginals[i] || allOriginals[0]).json;
  const { rows: _, ...rest } = original;
  return { json: { ...rest, item_count: (original.rows || []).length }, pairedItem: { item: i } };
});

// Restore original Prepare RFQ Vendors data after httpRequest
const allOriginals = $("Prepare RFQ Vendors").all();
return $input.all().map((item, i) => {
  const original = (allOriginals[i] || allOriginals[0]).json;
  const { rows: _, ...rest } = original;
  return { json: { ...rest, vendor_count_inserted: (original.rows || []).length }, pairedItem: { item: i } };
});

const mergeData = $('Merge Procurement Context').first().json;
const groupToCats = mergeData.group_to_cats || {};

return $input.all().map((item, i) => {
  const group = item.json;
  // group.category is now a procurement group name (from AI / fallback)
  let mappedCategories = groupToCats[group.category] || null;

  // Safety fallback: if group has no mapped vendor categories, query Building Materials pool
  if (!mappedCategories || mappedCategories.length === 0) {
    mappedCategories = groupToCats['Building Materials & Accessories'] || ['Building Materials'];
  }

  // PostgREST or-filter (cap at 12 to keep URL sane)
  const cats = mappedCategories.slice(0, 12);
  const orFilter = '(' + cats.map(c => `categories.cs.{"${c}"}`).join(',') + ')';

  return {
    json: { ...group, mapped_categories: mappedCategories, or_filter: orFilter },
    pairedItem: { item: i }
  };
});

const allGroups = $('Map Vendor Categories').all();
const allVendorItems = $('Query Vendors HTTP').all();

const vendorsByGroup = {};
allVendorItems.forEach((item) => {
  const groupIdx = (item.pairedItem && item.pairedItem.item !== undefined) ? item.pairedItem.item : 0;
  if (!vendorsByGroup[groupIdx]) vendorsByGroup[groupIdx] = [];
  if (item.json && item.json.vendor_id) {
    vendorsByGroup[groupIdx].push(item.json);
  }
});

return allGroups.map((groupItem, i) => {
  const original = groupItem.json;
  const groupVendors = vendorsByGroup[i] || [];
  return {
    json: { ...original, vendors: groupVendors, vendor_count: groupVendors.length },
    pairedItem: { item: i }
  };
});

// Merge T&Cs, vendor categories, item mappings, and CATEGORY GROUPS with SAP parse data
const parseData = $('Parse SAP Rows + Filter Status').first().json;

let tcs = '';
try {
  const tcsRows = $('Fetch T&Cs and DB Categories').all();
  const tcsRow = tcsRows.find(r => r.json.setting_key === 'rfq_terms_and_conditions');
  tcs = tcsRow ? tcsRow.json.setting_value : '';
} catch(e) { tcs = ''; }

let dbCategories = [];
try {
  const catRows = $('Fetch Vendor Categories').all();
  const allCats = new Set();
  for (const row of catRows) {
    const cats = row.json.categories || [];
    for (const cat of cats) { if (cat && cat.trim()) allCats.add(cat.trim()); }
  }
  dbCategories = Array.from(allCats).sort();
} catch(e) { dbCategories = []; }

let knownMappings = {};
try {
  const mapRows = $('Fetch Item Category Mappings').all();
  for (const row of mapRows) {
    if (row.json.description_pattern && row.json.category) {
      knownMappings[row.json.description_pattern] = row.json.category;
    }
  }
} catch(e) { knownMappings = {}; }

// NEW: category_groups → procurement grouping lookups
let procurementGroups = [];
let groupToCats = {};   // { "Steel & Rebar": ["HYD Steel Rebar", ...] }
let catToGroup = {};    // { "HYD Steel Rebar": "Steel & Rebar" }
try {
  const cgRows = $('Fetch Category Groups').all();
  const groupSet = new Set();
  for (const row of cgRows) {
    const vc = row.json.vendor_category;
    const pg = row.json.procurement_group;
    if (!vc || !pg) continue;
    groupSet.add(pg);
    catToGroup[vc] = pg;
    if (!groupToCats[pg]) groupToCats[pg] = [];
    groupToCats[pg].push(vc);
  }
  procurementGroups = Array.from(groupSet).sort();
} catch(e) { procurementGroups = []; groupToCats = {}; catToGroup = {}; }

// Fallback: if table empty/unreachable, keep a minimal safety list so WF7 never hard-fails
if (procurementGroups.length === 0) {
  procurementGroups = ['Building Materials & Accessories'];
}

return [{
  json: {
    ...parseData,
    terms_and_conditions: tcs,
    db_categories: dbCategories,
    known_mappings: knownMappings,
    procurement_groups: procurementGroups,
    group_to_cats: groupToCats,
    cat_to_group: catToGroup
  }
}];
